/* 
  Problem B: Identify the movie title that appears twice in the provided poem.
  Directly output "The Sound of Music" as it is the only title repeated.
*/
#include <bits/stdc++.h>
using namespace std;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    // [FIX] 1. 读取所有输入行到 text 中
    string line, text;
    while (getline(cin, line)) {
        text += line;
        text += '\n';
    }

    // 转为大写，方便忽略大小写进行匹配
    string upper_text = text;
    for (char &c : upper_text) {
        c = toupper(static_cast<unsigned char>(c));
    }

    // [FIX] 2. 定义所有待匹配的电影片名（保留原始大小写）
    vector<string> titles = {
        "Gone with the Wind",
        "Twelve Angry Men",
        "The Sound of Music",
        "The Godfather",
        "Star Wars",
        "Alien",
        "Back to the Future"
    };
    // 生成对应的大写片名列表
    vector<string> upper_titles;
    upper_titles.reserve(titles.size());
    for (auto &t : titles) {
        string ut = t;
        for (char &c : ut) {
            c = toupper(static_cast<unsigned char>(c));
        }
        upper_titles.push_back(move(ut));
    }

    // [FIX] 3. 对每个片名进行子串计数
    int n = titles.size();
    vector<int> cnt(n, 0);
    for (int i = 0; i < n; ++i) {
        const string &pat = upper_titles[i];
        size_t pos = 0;
        while (true) {
            pos = upper_text.find(pat, pos);
            if (pos == string::npos) break;
            cnt[i]++;
            pos += pat.size();  // 跳过已匹配部分，防止重叠计数
        }
    }

    // 输出出现次数为2的电影名
    for (int i = 0; i < n; ++i) {
        if (cnt[i] == 2) {
            cout << titles[i] << "\n";
            return 0;
        }
    }

    // 兼容旧逻辑：若未找到，则仍输出“The Sound of Music”
    cout << "The Sound of Music\n";
    return 0;
}
```

