string normalize(const string &s) {
    string t;
    t.reserve(s.size());
    // 转小写并替换非字母为' '
    for (char c : s) {
        if (isalpha(static_cast<unsigned char>(c))) {
            t += tolower(static_cast<unsigned char>(c));
        } else {
            t += ' ';
        }
    }
    // 压缩连续空格
    string u;
    u.reserve(t.size());
    bool in_space = false;
    for (char c : t) {
        if (c == ' ') {
            if (!in_space) {
                u += c;
                in_space = true;
            }
        } else {
            u += c;
            in_space = false;
        }
    }
    // 去除首尾空格后，再在头尾加一个空格
    int L = 0, R = (int)u.size() - 1;
    while (L <= R && u[L] == ' ') ++L;
    while (R >= L && u[R] == ' ') --R;
    string res = " ";
    if (L <= R) res += u.substr(L, R - L + 1);
    res += " ";
    return res;
}

