/* 
  Hero Proficiency Problem
  We solve the linear system for counts of operations on each hero (x_S, x_U, x_V),
  then schedule them in a safe order to avoid any proficiency dropping below zero.
*/
#include <bits/stdc++.h>
using namespace std;

int main(){
    ios::sync_with_stdio(false);
    cin.tie(NULL);

    int a[3];
    cin >> a[0] >> a[1] >> a[2];
    // If already two zeros, print empty
    int zeros = 0;
    for(int i = 0; i < 3; i++) if(a[i] == 0) zeros++;
    if(zeros >= 2){
        cout << "\n";
        return 0;
    }

    // 固定映射，保证仅输出 'Y','M','L'
    const char mp[3] = {'Y','M','L'};

    // Try each hero as survivor S
    for(int S = 0; S < 3; S++){
        int U = (S+1)%3, V = (S+2)%3;
        int U0 = a[U], V0 = a[V], S0 = a[S];
        // U0 + V0 必须为偶数才能抵消为 0
        if((U0 + V0) % 2) continue;
        int xS = (U0 + V0) / 2;
        int diff = V0 - U0;
        int xU = 0, xV = 0;
        if(diff >= 0) {
            // 需要 xU - xV == diff/2，diff>=0 则令 xU = diff/2
            xU = diff / 2;
        } else {
            // diff<0 则令 xV = (-diff)/2
            xV = (-diff) / 2;
        }
        // [FIX] S 在前两阶段共被扣减 xU + xV 次，必须保证 S0 >= xU + xV
        if(S0 < xU + xV) continue;
        int total = xS + xU + xV;
        if(total > 1000) continue;
        // We have a valid plan; construct the sequence
        string ans;
        ans.reserve(total);
        // First xU ops on U
        for(int i = 0; i < xU; i++){
            ans.push_back(mp[U]);
        }
        // Then xV ops on V
        for(int i = 0; i < xV; i++){
            ans.push_back(mp[V]);
        }
        // Finally xS ops on S
        for(int i = 0; i < xS; i++){
            ans.push_back(mp[S]);
        }
        cout << ans << "\n";
        return 0;
    }

    // If none of the survivors worked, print -1
    cout << "-1\n";
    return 0;
}

